create table "_RebateSchemaBundle"
(
    "Id"        bigint generated by default as identity
        constraint "_RebateSchemaBundle_pk"
            primary key,
    "Type"      integer                                                not null,
    "CreatedBy" bigint                                                 not null
        constraint "_RebateSchemaBundle__Party_Id_fk"
            references core."_Party",
    "CreatedOn" timestamp with time zone default now()                 not null,
    "UpdatedOn" timestamp with time zone default now()                 not null,
    "Name"      varchar(64)                                            not null,
    "Note"      varchar(256)             default ''::character varying not null,
    "Data"      jsonb                    default '[]'::jsonb           not null
);

alter table "_RebateSchemaBundle"
    owner to bcrpro;

create index "_RebateSchemaBundle_CreatedBy_index"
    on "_RebateSchemaBundle" ("CreatedBy");

create unique index "_RebateSchemaBundle_Name_Type_uindex"
    on "_RebateSchemaBundle" ("Name", "Type");

grant select on "_RebateSchemaBundle" to dev_read;

